import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import he from '../i18n/he.json';

export default function CheckoutForm() {
  const [form, setForm] = useState({
    name: '',
    phone: '',
    address: '',
    coupon: '',
    paymentMethod: 'cash',
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post('http://localhost:4000/api/orders', {
        name: form.name,
        phone: form.phone,
        address: form.address,
        coupon: form.coupon || null,
        paymentMethod: form.paymentMethod,
        toppings: cart.toppings,
        total: cart.total,
        createdAt: new Date().toISOString(),
      });
      localStorage.removeItem('cart');
      navigate('/success');
    } catch (err) {
      alert('שגיאה בשליחת ההזמנה');
    } finally {
      setLoading(false);
    }
  };

  if (!cart.toppings) {
    return null;
  }

  return (
    <form onSubmit={handleSubmit} className="max-w-md mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg">
      <h2 className="text-xl mb-4 text-tomato">{he.checkout}</h2>

      <div className="mb-3">
        <label className="block mb-1">{he.name}</label>
        <input
          name="name"
          value={form.name}
          onChange={handleChange}
          required
          className="w-full border rounded-lg px-3 py-2 focus:outline-tomato"
        />
      </div>

      <div className="mb-3">
        <label className="block mb-1">{he.phone}</label>
        <input
          name="phone"
          type="tel"
          value={form.phone}
          onChange={handleChange}
          required
          className="w-full border rounded-lg px-3 py-2 focus:outline-tomato"
          dir="ltr"
        />
      </div>

      <div className="mb-3">
        <label className="block mb-1">{he.address}</label>
        <input
          name="address"
          value={form.address}
          onChange={handleChange}
          required
          className="w-full border rounded-lg px-3 py-2 focus:outline-tomato"
        />
      </div>

      <div className="mb-3">
        <label className="block mb-1">{he.coupon_code}</label>
        <input
          name="coupon"
          value={form.coupon}
          onChange={handleChange}
          placeholder="הכנס קוד קופון (אופציונלי)"
          className="w-full border rounded-lg px-3 py-2 focus:outline-tomato"
        />
      </div>

      <div className="mb-4">
        <label className="block mb-2">{he.payment_method}</label>
        <div className="flex gap-4">
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="paymentMethod"
              value="cash"
              checked={form.paymentMethod === 'cash'}
              onChange={handleChange}
              className="accent-tomato w-4 h-4"
            />
            <span>{he.cash}</span>
          </label>
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              name="paymentMethod"
              value="credit"
              checked={form.paymentMethod === 'credit'}
              onChange={handleChange}
              className="accent-tomato w-4 h-4"
            />
            <span>{he.credit}</span>
          </label>
        </div>
      </div>

      <div className="font-bold text-lg mt-4 flex justify-between">
        <span>{he.total}:</span>
        <span>{cart.total} ₪</span>
      </div>
      <button
        type="submit"
        className="w-full bg-tomato text-white py-2 rounded-lg font-bold text-lg mt-4 hover:bg-red-700 transition"
        disabled={loading}
      >
        {loading ? 'שולח...' : he.place_order}
      </button>
    </form>
  );
}
